import React, { useState } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Alert,
  Box,
  CircularProgress,
  ToggleButton,
  ToggleButtonGroup,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import api from "../services/api"; // default export

export default function Register() {
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    mobile: "",
    role: "user",
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Handle input change
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // Handle role toggle
  const handleRoleChange = (e, newRole) => {
    if (newRole) setFormData({ ...formData, role: newRole.toLowerCase() });
  };

  // Mobile validation
  const validateMobile = (mobile) => /^[6-9]\d{9}$/.test(mobile);

  // Submit handler
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!validateMobile(formData.mobile)) {
      setError("Mobile number must start with 6-9 and be 10 digits long.");
      return;
    }

    try {
      setLoading(true);
      const res = await api.signup(formData); // using default export

      if (res.success) {
        navigate("/login"); // redirect to login after successful registration
      } else {
        setError(res.message || "Registration failed.");
      }
    } catch (err) {
      setError("Server error. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography
          variant="h4"
          align="center"
          sx={{ color: "orange", fontWeight: "bold" }}
          gutterBottom
        >
          Rider App
        </Typography>
        <Typography align="center" sx={{ mb: 3 }}>
          Create your account
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField
            fullWidth
            label="Full Name"
            name="fullName"
            value={formData.fullName}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="Email"
            name="email"
            type="email"
            value={formData.email}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            label="Mobile Number"
            name="mobile"
            value={formData.mobile}
            onChange={handleChange}
            margin="normal"
            inputProps={{ maxLength: 10 }}
            required
          />

          <Typography sx={{ mt: 2 }}>Role</Typography>
          <ToggleButtonGroup
            value={formData.role}
            exclusive
            onChange={handleRoleChange}
            fullWidth
            sx={{ mb: 2 }}
          >
            <ToggleButton value="user">USER</ToggleButton>
            <ToggleButton value="owner">OWNER</ToggleButton>
          </ToggleButtonGroup>

          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ bgcolor: "orange", "&:hover": { bgcolor: "#ff6600" } }}
            disabled={loading}
          >
            {loading ? <CircularProgress size={24} color="inherit" /> : "REGISTER"}
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}
